CREATE VIEW `ads_user_reinstalllog_view` (`product_Id` COMMENT "产品id", `id` COMMENT "编号id", `create_time` COMMENT "记录时间", `app_id` COMMENT "应用程序id", `user_id` COMMENT "用户id", `core` COMMENT "Core", `mt` COMMENT "mt", `pre_app_id` COMMENT "上一次的AppId", `pre_core` COMMENT "上一次的Core", `pre_mt` COMMENT "上一次的mt", `unique_cd_reader_id` COMMENT "设备信息", `status` COMMENT "Ads使用,判断是否被用过了", `pre_login_time` COMMENT "上一次登录时间", `days` COMMENT "流失天数", `re_install_type` COMMENT "再安装类型")
COMMENT "再安装日志表" AS SELECT `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`Product_Id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`Id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`CreateTime` AS `create_time`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`AppId` AS `app_id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`UserId` AS `user_id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`Core`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`Mt`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`PreAppId` AS `pre_app_id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`PreCore` AS `pre_core`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`PreMt` AS `pre_mt`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`UniqueCdReaderId` AS `unique_cd_reader_id`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`status`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`PreLoginTime` AS `pre_login_time`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`Days`, `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`.`ReInstallType` AS `re_install_type`
FROM `ods_log`.`ods_tidb_readerlog_xx_Log_ReInstallLog`;